BEGIN;

-- -----------------------------------------------------------------------------
-- Step 1: Rename mismatched codes to match the active instance registry
-- -----------------------------------------------------------------------------
UPDATE organizations SET code = 'siden-cfo', name = 'siden-cfo', app_url = 'https://siden-cfo.ideacarb.com', account_type = 'employee', updated_at = NOW()
WHERE lower(code) = 'sid-en';

UPDATE organizations SET code = 'siden-kwn', name = 'siden-kwn', app_url = 'https://siden-kwn.ideacarb.com', account_type = 'employee', updated_at = NOW()
WHERE lower(code) = 'sid-en-kwn';

-- -----------------------------------------------------------------------------
-- Step 2: Insert 4 active instances missing from admin console
-- -----------------------------------------------------------------------------
WITH admin_user AS (
  SELECT id
  FROM users
  WHERE email = 'admin@cfo.com'
  LIMIT 1
),
missing_orgs AS (
  SELECT *
  FROM (
    VALUES
      ('gamma', 'gamma', 'https://gamma.ideacarb.com', 'employee'),
      ('srt', 'srt', 'https://srt.ideacarb.com', 'general customers'),
      ('srt-demo', 'srt-demo', 'https://srt-demo.ideacarb.com', 'general customers'),
      ('tgo-test', 'tgo-test', 'https://tgo-test.ideacarb.com', 'employee')
  ) AS t(name, code, app_url, account_type)
)
INSERT INTO organizations (
  name,
  code,
  app_url,
  account_type,
  is_initialized,
  created_by
)
SELECT
  mo.name,
  mo.code,
  mo.app_url,
  mo.account_type,
  FALSE,
  (SELECT id FROM admin_user)
FROM missing_orgs mo
ON CONFLICT (code) DO UPDATE
SET
  name = EXCLUDED.name,
  app_url = EXCLUDED.app_url,
  account_type = EXCLUDED.account_type,
  updated_at = NOW();

